class Solution:
    def maxDistance(self, arrays: List[List[int]]) -> int:
        mn, mx, ans = arrays[0][0], arrays[0][-1], 0
        for arr in arrays[1:]:
            ans = max(ans, abs(arr[-1]-mn), abs(mx-arr[0]))
            mn = min(mn, arr[0]); mx = max(mx, arr[-1])
        return ans

