class Solution {
public:
    int maxDistance(vector<vector<int>>& a) {
        int mn=a[0][0], mx=a[0].back(), ans=0;
        for(int i=1;i<(int)a.size();i++){
            ans=max({ans, abs(a[i].back()-mn), abs(mx-a[i][0])});
            mn=min(mn,a[i][0]); mx=max(mx,a[i].back());
        }
        return ans;
    }
};

